sql:
SELECT a.athlete_id, a.name
FROM athletes a
WHERE a.athlete_id IN (SELECT ac.athlete_id FROM athlete_competitions ac);

SELECT username 
FROM admin_users 
WHERE admin_user_id = 1;

SELECT admin_user_id, username
FROM admin_users
WHERE admin_user_id NOT IN (
  SELECT athlete_id
  FROM athlete_competitions
);

SELECT name 
FROM athletes 
WHERE equipment = 0;

SELECT MAX(age)
FROM athletes
WHERE athlete_id IN (
  SELECT athlete_id
  FROM athlete_competitions
);

SELECT name 
FROM athletes 
WHERE athlete_id IN (SELECT athlete_id FROM athlete_competitions);

external_knowledge:
Seasoned athletes: Athletes over the age of 25;
Exceptional performance: Weight lifted above the average;
Active competitions: Competitions marked as active in the database;
Three-quarters of the highest weight: 75% of the maximum weight lifted;
Total and average weight lifted: The sum and average of the weight lifted by each athlete across all their competitions.

sql:
SELECT a.name
FROM athletes a
INNER JOIN competition_results cr ON a.athlete_id = cr.athlete_id;

SELECT username
FROM admin_users
WHERE admin_user_id = (
    SELECT MIN(admin_user_id)
    FROM admin_users
    WHERE admin_user_id NOT IN (
        SELECT admin_user_id
        FROM athlete_competitions
    )
);
